<template>
  <div>
    <el-breadcrumb separator="/" style="padding-left: 10px;padding-bottom: 10px;font-size: 12px">
      <el-breadcrumb-item :to="{ path: '/main' }">首页</el-breadcrumb-item>
      <el-breadcrumb-item>系统管理</el-breadcrumb-item>
      <el-breadcrumb-item>我的应聘</el-breadcrumb-item>
    </el-breadcrumb>

    <el-card class="box-card">
      <el-form :inline="true" :model="dataVo" class="demo-form-inline">
        <el-form-item label="简历名称" label-width="70px">
          <el-input clearable v-model="dataVo.rtitle" placeholder="请输入简历名称"></el-input>
        </el-form-item>
        <el-form-item label="岗位名称" label-width="70px">
          <el-input clearable v-model="dataVo.rname" placeholder="请输入岗位名称"></el-input>
        </el-form-item>
        <el-form-item label="公司名称" label-width="70px">
          <el-input clearable v-model="dataVo.cname" placeholder="请输入公司名称"></el-input>
        </el-form-item>
        <el-form-item style="margin-left: 10px">
          <el-button icon="el-icon-refresh" @click="resetDataVo">重置</el-button>
          <el-button type="primary" icon="el-icon-search" @click="getDataList">查询</el-button>
        </el-form-item>
      </el-form>
      <el-table
        :data="dataList"
        border
        max-height="400"
        style="width: 100%;">
        <el-table-column
          prop="id"
          label="#"
          type="index"
          width="50">
        </el-table-column>
        <el-table-column
          prop="rtitle"
          label="简历名称"
          width="120">
        </el-table-column>
        <el-table-column
          prop="rname"
          label="岗位名称"
          width="120">
        </el-table-column>
        <el-table-column
          sortable
          prop="rdate"
          label="添加日期"
          width="100">
          <template slot-scope="scope">
            {{scope.row.rdate}}
          </template>
        </el-table-column>
        <el-table-column
          prop="cname"
          label="公司名称"
          width="150">
        </el-table-column>
        <el-table-column
          prop="ctel"
          label="公司电话"
          width="110">
        </el-table-column>
        <el-table-column
          prop="cattr"
          label="所在位置"
          width="150">
        </el-table-column>
        <el-table-column
          prop="cmajor"
          label="服务范围"
          width="120">
        </el-table-column>
        <el-table-column
          prop="rintroduce"
          label="公司介绍"
          width="220">
        </el-table-column>
        <el-table-column
          sortable
          prop="tname"
          label="简历类型"
          width="180">
        </el-table-column>
        <el-table-column
          sortable
          prop="astuts"
          label="应聘状态"
          width="180">
        </el-table-column>
        <el-table-column
          label="操作" width="120">
          <template slot-scope="scope">
            <el-button type="danger" size="mini" v-if="scope.row.aflag == 0"
                       icon="el-icon-delete" @click="deleteDatas(scope.row.id)" title="取消应聘"></el-button>
            <el-button type="danger" size="mini" v-if="scope.row.aflag == 3"
                       icon="el-icon-delete" @click="agreesigntriagreementDatas(scope.row.id)" title="同意签订三方协议"></el-button>
            <el-button type="danger" size="mini" v-if="scope.row.aflag == 3"
                       icon="el-icon-delete" @click="noagreesigntriagreementDatas(scope.row.id)" title="不同意签订三方协议"></el-button>
          </template>
        </el-table-column>
      </el-table>
      <el-pagination
        style="padding-top: 15px"
        @size-change="handleSizeChange"
        @current-change="handleCurrentChange"
        :current-page="current"
        :page-sizes="[6, 10, 20, 30]"
        :page-size="size"
        layout="total, sizes, prev, pager, next, jumper"
        :total="total">
      </el-pagination>
    </el-card>
  </div>

</template>

<script>
  import { findUserApplysDatasForUserList,deleteUserApplysDatas,agreesigntriagreementDatas,
    noagreesigntriagreementDatas } from '../../api/resumes';

  export default {
    name: 'MyApplys',
    data() {
      return {
        dataVo: {
          rtitle:'',
          rname:'',
          cname:''
        },
        addOrUpdateVisible: false,
        editOrUpdateVisible: false,
        dataList: [],
        size: 6,
        total: 100,
        current: 1
      };
    },
    components: {
    },
    created(){
      this.getDataList();
    },
    methods: {
      onSubmit() {
      },
      handleSizeChange(val) {
        this.size = val;
        this.getDataList();
      },
      handleCurrentChange(val) {
        this.current = val;
        this.getDataList();
      },
      async getDataList(){
        if(this.$session.get("phone") == null)
          this.$router.push("/login");
        const { data } = await findUserApplysDatasForUserList(this.current,this.size,this.dataVo,this.$session.get("phone"));
        this.dataList = data.data.records;
        this.total = data.data.total;
      },
      resetDataVo(){
        this.dataVo.rtitle = '';
        this.dataVo.cname = '';
        this.dataVo.rname = '';
        this.getDataList();
      },
      show(){
        this.addOrUpdateVisible = true;
      },
      agreesigntriagreementDatas(id){
        var that = this;
        this.$confirm('此操作将同意签订三方协议 是否继续?', '提示', {
          confirmButtonText: '确定',
          cancelButtonText: '取消',
          type: 'warning'
        }).then(() => {
          agreesigntriagreementDatas(id);
          this.$message({
            type: 'success',
            message: '取消应聘成功!'
          });
          that.getDataList();
        }).catch(() => {
          this.$message({
            type: 'info',
            message: '已取消删除'
          });
        });
      },
      noagreesigntriagreementDatas(id){
        var that = this;
        this.$confirm('此操作将不同意签订三方协议 是否继续?', '提示', {
          confirmButtonText: '确定',
          cancelButtonText: '取消',
          type: 'warning'
        }).then(() => {
          noagreesigntriagreementDatas(id);
          this.$message({
            type: 'success',
            message: '取消应聘成功!'
          });
          that.getDataList();
        }).catch(() => {
          this.$message({
            type: 'info',
            message: '已取消删除'
          });
        });
      },
      deleteDatas(id){
        var that = this;
        this.$confirm('此操作将取消应聘, 是否继续?', '提示', {
          confirmButtonText: '确定',
          cancelButtonText: '取消',
          type: 'warning'
        }).then(() => {
          deleteUserApplysDatas(id);
          this.$message({
            type: 'success',
            message: '取消应聘成功!'
          });
          that.getDataList();
        }).catch(() => {
          this.$message({
            type: 'info',
            message: '已取消删除'
          });
        });
      },
       dataEdit(row){
        var that = this;
         this.editOrUpdateVisible = true;
        this.$nextTick(() => {
            that.$refs.eidtOrUpdateRef.dataInit(row);
        });
         this.getDataList();
        console.log(this.dataEdit);
      },
      showAddOrUpdate(data){
        if(data === 'false'){
          this.addOrUpdateVisible = false;
        }else{
          this.addOrUpdateVisible = true;
        }
        this.getDataList();
      },
      showEidtOrUpdate(data){
        if(data === 'false'){
          this.editOrUpdateVisible = false;
        }else{
          this.editOrUpdateVisible = true;
        }
        this.getDataList();
      }
    }
  };
</script>

<style scoped>

</style>
